import { describe, expect, it } from 'vitest';
import {
  solarDeclination,
  equationOfTime,
  classifyTwilightZone,
  twilightZoneFraction,
  solarPosition,
  isDaylightAtPLo,
  solarPositionAtPLo,
  solarPhase,
  solarPhaseContinuous,
  solarHalfDay,
  toPicolorenzos,
} from './math';

describe('solarDeclination', () => {
  it('returns near -23.4 at winter solstice (doy ~355)', () => {
    const dec = solarDeclination(355);
    expect(dec).toBeLessThan(-20);
    expect(dec).toBeGreaterThan(-24);
  });

  it('returns near +23.4 at summer solstice (doy ~172)', () => {
    const dec = solarDeclination(172);
    expect(dec).toBeGreaterThan(20);
    expect(dec).toBeLessThan(24);
  });

  it('returns near 0 at equinox (doy ~80)', () => {
    const dec = solarDeclination(80);
    expect(Math.abs(dec)).toBeLessThan(5);
  });
});

describe('equationOfTime', () => {
  it('returns a value in the expected range (-17 to +14 minutes)', () => {
    for (let doy = 1; doy <= 365; doy++) {
      const eot = equationOfTime(doy);
      expect(eot).toBeGreaterThan(-20);
      expect(eot).toBeLessThan(20);
    }
  });
});

describe('classifyTwilightZone', () => {
  it('classifies day when altitude > 0', () => {
    expect(classifyTwilightZone(45)).toBe('day');
    expect(classifyTwilightZone(0.1)).toBe('day');
  });

  it('classifies civil twilight when -6 < altitude <= 0', () => {
    expect(classifyTwilightZone(0)).toBe('civil');
    expect(classifyTwilightZone(-3)).toBe('civil');
    expect(classifyTwilightZone(-5.9)).toBe('civil');
  });

  it('classifies nautical twilight when -12 < altitude <= -6', () => {
    expect(classifyTwilightZone(-6)).toBe('nautical');
    expect(classifyTwilightZone(-9)).toBe('nautical');
  });

  it('classifies astronomical twilight when -18 < altitude <= -12', () => {
    expect(classifyTwilightZone(-12)).toBe('astronomical');
    expect(classifyTwilightZone(-15)).toBe('astronomical');
  });

  it('classifies night when altitude <= -18', () => {
    expect(classifyTwilightZone(-18)).toBe('night');
    expect(classifyTwilightZone(-45)).toBe('night');
  });
});

describe('twilightZoneFraction', () => {
  it('returns 0 at the lower boundary of a zone', () => {
    // nautical zone: -12 to -6. At -12, it is classified as astronomical
    // (boundary belongs to the zone below), so fraction is 1 (top of astronomical).
    // Within nautical at -11, fraction should be close to the bottom.
    expect(twilightZoneFraction(-11)).toBeCloseTo(1 / 6, 1);
    // civil zone: at -5.9, fraction should be near 0 (just above lower bound)
    expect(twilightZoneFraction(-5.9)).toBeCloseTo(0.017, 1);
  });

  it('returns 1 at the upper boundary of a zone', () => {
    // civil zone: -6 to 0, altitude = 0 is at boundary (classified as civil)
    // Actually 0 is at the boundary -- let's check a value just below
    expect(twilightZoneFraction(-0.01)).toBeGreaterThan(0.99);
  });

  it('returns 0.5 at the midpoint of a zone', () => {
    // civil zone: -6 to 0, midpoint is -3
    expect(twilightZoneFraction(-3)).toBeCloseTo(0.5, 1);
  });
});

describe('solarPosition', () => {
  it('returns high altitude at equator solar noon', () => {
    // March 20, 2026, 12:00 UTC at equator, prime meridian
    // Near equinox, sun should be near zenith at equator at noon
    const equinoxNoon = Date.UTC(2026, 2, 20, 12, 0, 0);
    const pos = solarPosition({ latitudeDeg: 0, longitudeDeg: 0 }, equinoxNoon);
    expect(pos.altitudeDeg).toBeGreaterThan(60);
    expect(pos.zone).toBe('day');
  });

  it('returns negative altitude at equator midnight', () => {
    // March 20, 2026, 00:00 UTC at equator, prime meridian
    const equinoxMidnight = Date.UTC(2026, 2, 20, 0, 0, 0);
    const pos = solarPosition({ latitudeDeg: 0, longitudeDeg: 0 }, equinoxMidnight);
    expect(pos.altitudeDeg).toBeLessThan(0);
    expect(pos.zone).not.toBe('day');
  });

  it('returns daylight at longitude 180 when UTC is midnight', () => {
    // When it is midnight at prime meridian, it is noon at 180 degrees
    const midnight = Date.UTC(2026, 2, 20, 0, 0, 0);
    const pos = solarPosition({ latitudeDeg: 0, longitudeDeg: 180 }, midnight);
    expect(pos.altitudeDeg).toBeGreaterThan(40);
    expect(pos.zone).toBe('day');
  });

  it('returns azimuth in [0, 360)', () => {
    const noon = Date.UTC(2026, 5, 15, 12, 0, 0);
    const pos = solarPosition({ latitudeDeg: 40, longitudeDeg: -74 }, noon);
    expect(pos.azimuthDeg).toBeGreaterThanOrEqual(0);
    expect(pos.azimuthDeg).toBeLessThan(360);
  });
});

describe('isDaylightAtPLo', () => {
  it('returns true at solar noon', () => {
    const noonDate = new Date(Date.UTC(2026, 5, 21, 12, 0, 0));
    const pLo = toPicolorenzos(noonDate);
    expect(isDaylightAtPLo(pLo, { latitudeDeg: 0, longitudeDeg: 0 })).toBe(true);
  });

  it('returns false at solar midnight', () => {
    const midnightDate = new Date(Date.UTC(2026, 5, 21, 0, 0, 0));
    const pLo = toPicolorenzos(midnightDate);
    expect(isDaylightAtPLo(pLo, { latitudeDeg: 0, longitudeDeg: 0 })).toBe(false);
  });
});

describe('solarPhase', () => {
  it('returns 1 during day and 0 during night', () => {
    const noonPLo = toPicolorenzos(new Date(Date.UTC(2026, 5, 21, 12, 0, 0)));
    const midnightPLo = toPicolorenzos(new Date(Date.UTC(2026, 5, 21, 0, 0, 0)));
    const observer = { latitudeDeg: 0, longitudeDeg: 0 };

    expect(solarPhase(noonPLo, observer)).toBe(1);
    expect(solarPhase(midnightPLo, observer)).toBe(0);
  });
});

describe('solarPhaseContinuous', () => {
  it('returns value near 1 at noon and near 0 at midnight', () => {
    const noonPLo = toPicolorenzos(new Date(Date.UTC(2026, 5, 21, 12, 0, 0)));
    const midnightPLo = toPicolorenzos(new Date(Date.UTC(2026, 5, 21, 0, 0, 0)));
    const observer = { latitudeDeg: 0, longitudeDeg: 0 };

    expect(solarPhaseContinuous(noonPLo, observer)).toBeGreaterThan(0.7);
    expect(solarPhaseContinuous(midnightPLo, observer)).toBeLessThan(0.3);
  });

  it('returns values in [0, 1]', () => {
    const observer = { latitudeDeg: 45, longitudeDeg: -90 };
    for (let h = 0; h < 24; h++) {
      const pLo = toPicolorenzos(new Date(Date.UTC(2026, 2, 20, h, 0, 0)));
      const phase = solarPhaseContinuous(pLo, observer);
      expect(phase).toBeGreaterThanOrEqual(0);
      expect(phase).toBeLessThanOrEqual(1);
    }
  });
});

describe('solarHalfDay', () => {
  it('returns near 50% lit fraction at equator during equinox', () => {
    const equinoxPLo = toPicolorenzos(new Date(Date.UTC(2026, 2, 20, 6, 0, 0)));
    const observer = { latitudeDeg: 0, longitudeDeg: 0 };
    const half = solarHalfDay(equinoxPLo, observer);

    expect(half.litFraction).toBeGreaterThan(0.4);
    expect(half.litFraction).toBeLessThan(0.6);
    expect(half.litDurationPLo + half.darkDurationPLo).toBeCloseTo(1 / Math.PI, 3);
  });

  it('returns higher lit fraction at high latitudes in summer', () => {
    const summerPLo = toPicolorenzos(new Date(Date.UTC(2026, 5, 21, 0, 0, 0)));
    const arcticObserver = { latitudeDeg: 65, longitudeDeg: 0 };
    const half = solarHalfDay(summerPLo, arcticObserver);

    // Arctic summer should have very long days
    expect(half.litFraction).toBeGreaterThan(0.7);
  });
});
